const productor = $items('Get Productor Vilma')[0].json;
if (!productor || !productor.id) {
  throw new Error('Productor Vilma no encontrado en Supabase');
}
const matches = $input.all().map((i) => i.json).filter((m) => m && m.oportunidad_id);
if (!matches.length) {
  throw new Error('Sin oportunidades match para el productor');
}
matches.sort((a, b) => (Number(b.score) || 0) - (Number(a.score) || 0) || (Number(b.monto) || 0) - (Number(a.monto) || 0));
const row = matches[0];
const monto = Number(row.monto || 0);
const oportunidadDetectada = `${row.titulo} de ${row.institucion} por $${monto.toLocaleString('en-US')} con cierre ${row.fecha_cierre}.`;
return [{
  json: {
    agent_id: 'agent_9801kwr61ctre7x8c944ze53p95w',
    phone_number: productor.telefono,
    dynamic_variables: {
      productor_id: productor.id,
      oportunidad_id: row.oportunidad_id,
      nombre_productor: productor.nombre,
      rubro_negocio: productor.rubro,
      capacidad_productor: productor.capacidad,
      oportunidad_detectada: oportunidadDetectada,
      oportunidad_titulo: row.titulo,
      oportunidad_institucion: row.institucion,
      oportunidad_monto: monto,
      oportunidad_cierre: row.fecha_cierre,
      unspsc_code: row.unspsc_code || '',
      url_fuente: row.url_fuente || '',
      score_match: Number(row.score || 0)
    },
    metadata: {
      productor_id: productor.id,
      oportunidad_id: row.oportunidad_id,
      source: 'compa-fase-3-n8n'
    },
    first_message: `Doña ${productor.nombre.split(' ')[0]}, como esta? Habla Compa. Vi una oportunidad para su negocio: ${oportunidadDetectada} Tiene un momento para revisarla?`
  }
}];
